// Nó da lista circular
class Node {
    public int Value;
    public Node Next;  // último nó aponta para HEAD
    public Node(int value) { Value = value; }
}

// Inserção no início — O(n) para atualizar ponteiro do último nó
void InsertBegin(ref Node head, int value) {
    Node newNode = new Node(value);
    if (head == null) {
        newNode.Next = newNode;  // aponta para si mesmo
        head = newNode;
        return;
    }
    // Encontra o último nó (tail.next == head)
    Node tail = head;
    while (tail.Next != head) tail = tail.Next;
    newNode.Next = head;
    tail.Next    = newNode;  // tail agora aponta para o novo HEAD
    head         = newNode;
}

