type Node struct {
	Value int
	Next  *Node
}

func insertBegin(head **Node, value int) {
	newNode := &Node{Value: value}
	if *head == nil {
		newNode.Next = newNode // aponta para si mesmo
		*head = newNode
		return
	}
	tail := *head
	for tail.Next != *head {
		tail = tail.Next
	}
	newNode.Next = *head
	tail.Next = newNode // tail agora aponta para o novo head
	*head = newNode
}

