class Node:
    def __init__(self, value):
        self.value = value
        self.next  = None  # último nó aponta de volta para head

class CircularList:
    def __init__(self):
        self.head = None

    def insert_begin(self, value):
        new_node = Node(value)
        if self.head is None:
            new_node.next = new_node  # lista de um nó — aponta para si
            self.head = new_node
            return
        # Percorre até o último nó
        tail = self.head
        while tail.next != self.head:
            tail = tail.next
        new_node.next = self.head
        tail.next     = new_node  # tail passa a apontar para o novo head
        self.head     = new_node

    def traverse(self):
        if not self.head:
            return
        current = self.head
        while True:
            print(current.value)
            current = current.next
            if current == self.head:  # parada: voltou ao início
                break

