class Node {
    constructor(value) {
        this.value = value;
        this.next  = null;
    }
}

class CircularList {
    constructor() { this.head = null; }

    insertBegin(value) {
        const node = new Node(value);
        if (!this.head) {
            node.next  = node;   // único nó aponta para si mesmo
            this.head  = node;
            return;
        }
        // Acha o tail (tail.next === head)
        let tail = this.head;
        while (tail.next !== this.head) tail = tail.next;
        node.next  = this.head;
        tail.next  = node;       // tail atualizado
        this.head  = node;
    }

    traverse() {
        if (!this.head) return;
        let cur = this.head;
        do {
            console.log(cur.value);
            cur = cur.next;
        } while (cur !== this.head);  // para ao voltar ao HEAD
    }
}
